+    use colored::Colorize;
+
+    let path = allowlist_path_for_layer(layer);
+    let mut doc = load_or_create_allowlist_doc(&path)?;
+
+    // Check for duplicate
+    if has_command_entry(&doc, command) {
+        println!(
+            "{} Command already exists in {} allowlist",
